mapper.select:
SELECT a.id, a.asset_code, a.asset_name, a.category_id, c.category_name, a.brand, a.specification, a.department, a.keeper, a.location, a.original_value, a.net_value, a.status, a.purchase_date FROM asset a LEFT JOIN asset_category c ON c.id = a.category_id
a.deleted = 0
AND a.asset_code LIKE CONCAT('%', #{query.assetCode}, '%')
AND a.asset_name LIKE CONCAT('%', #{query.assetName}, '%')
AND a.category_id = #{query.categoryId}
AND a.department LIKE CONCAT('%', #{query.department}, '%')
AND a.keeper LIKE CONCAT('%', #{query.keeper}, '%')
AND a.location LIKE CONCAT('%', #{query.location}, '%')
AND a.status = #{query.status}
AND a.purchase_date >= #{query.purchaseDateStart}
AND a.purchase_date <= #{query.purchaseDateEnd}
ORDER BY a.updated_at DESC, a.id DESC
